#!/usr/bin/env node
/**
 * docgen — per-directory README generator for Claude agents.
 *
 * Walks the repo, picks one (or all, with --until-done) directories
 * whose contents have changed since the last analysis (or were never
 * analyzed), feeds the directory's file content to `claude -p`, and
 * writes the response to `<dir>/README.md` with an auto-generated
 * marker so humans and agents know it isn't hand-written.
 *
 * State (which dirs have been analyzed, with what file mtimes) lives
 * at `.docgen/state.json` at repo root. Staleness = any file added,
 * removed, or modified since last analysis.
 *
 * The whole point is to make Claude faster at navigating the codebase:
 * a stale grep / find isn't as good as a one-paragraph "this directory
 * does X, files are Y/Z/W, depends on A" written by a previous agent
 * with full context.
 *
 * USAGE
 *   docgen                       analyze one stale/uncovered dir, exit
 *   docgen --until-done          loop until every dir has fresh docs
 *   docgen --until-done --parallel 4   same, but up to 4 dirs in flight
 *                                  at the same tree depth — leaves at
 *                                  depth N parallelise, trunks at N-1
 *                                  wait for their children.
 *   docgen status                print coverage report (no analysis)
 *   docgen --dir <path>          force-analyze a specific directory
 *   docgen --force --dir <path>  overwrite a hand-written README (opt-in)
 *   docgen --dry-run             print what would be analyzed, do not call claude
 *   docgen --help                show this help
 *
 *   --parallel <n>               max concurrent claude calls within a
 *                                depth batch (default 1 — serial). Only
 *                                dirs at the same depth ever run
 *                                concurrently; bottom-up ordering is
 *                                preserved across depths.
 *   --model <name>               override claude model (default: cli default)
 *   --timeout-ms <n>             per-call timeout (default 300000 = 5 min)
 *
 * The CLI is designed for one-shot invocation by humans, cron, or a
 * future PR-merge hook. State is durable; rerunning picks up where the
 * last run stopped.
 *
 * No shell execution: all subprocess calls use `spawn` / `execFileSync`
 * with explicit argv arrays — no string interpolation reaches a shell,
 * so user-supplied flags can't shell-inject.
 */

import {
  existsSync,
  mkdirSync,
  readdirSync,
  readFileSync,
  realpathSync,
  statSync,
  writeFileSync,
} from 'node:fs';
import { spawn, execFileSync } from 'node:child_process';
import { dirname, extname, join, relative, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

// ─── config ───────────────────────────────────────────────────────────────

const MARKER =
  '<!-- auto-generated by docgen — do not hand-edit. Run `tools/docgen/docgen` to refresh. -->';

/** A short prefix of the marker — used to recognise auto-gen READMEs
 *  without being tripped up by cosmetic re-wording of the full marker. */
const MARKER_DETECT_PREFIX = '<!-- auto-generated by docgen';

/** Dir-name skips (any directory at any depth named these is pruned). */
const SKIP_DIRS = new Set([
  'node_modules',
  '.git',
  'dist',
  'build',
  '.tooling',
  '.docgen',
  '.next',
  '.cache',
  'coverage',
  '__pycache__',
  '.venv',
  'venv',
  '.pytest_cache',
  '.turbo',
  '.parcel-cache',
]);

/** File extension skips (binary / lock / huge). The actual size cap below
 *  catches anything we missed by extension. */
const SKIP_FILE_EXT = new Set([
  '.lock', '.lockb',
  '.png', '.jpg', '.jpeg', '.gif', '.svg', '.ico', '.webp',
  '.pdf', '.zip', '.tar', '.gz', '.bz2', '.xz', '.7z',
  '.mp3', '.mp4', '.mov', '.wav', '.webm',
  '.bin', '.wasm', '.so', '.dylib', '.dll', '.exe',
  '.ttf', '.otf', '.woff', '.woff2', '.eot',
]);

/** Per-file cap for the prompt. Larger files get truncated with a marker
 *  so the LLM knows it's not the full content. */
const MAX_FILE_BYTES_FOR_PROMPT = 8 * 1024;
/** Skip individual files larger than this even after truncation. */
const MAX_FILE_BYTES_HARD = 1024 * 1024;
/** Skip a directory entirely if it has more than this many files —
 *  generated-asset dirs (build outputs, large fixture sets) bloat the
 *  prompt without informational value. */
const MAX_FILES_PER_DIR = 60;

/** Curated-context filenames (see collectCuratedContext for behavior).
 *  Maintainers drop these to inject hand-written guidance into the
 *  prompt without putting hand-written content inside the generated
 *  README itself (which keeps the README cleanly regeneratable). */
const CTX_GLOBAL_PATH = '.docgen/global.md';
const CTX_LOCAL_FILENAME = '.docgen-context.md';
const CTX_CASCADE_FILENAME = '.docgen-cascade.md';
/** Cap per-context-file bytes folded into the prompt. */
const MAX_CTX_BYTES = 4 * 1024;

const DEFAULT_TIMEOUT_MS = 5 * 60 * 1000;

// ─── repo + state ─────────────────────────────────────────────────────────

function repoRoot() {
  // Allow override for tests so we don't touch the real repo.
  if (process.env.DOCGEN_REPO_ROOT) return resolve(process.env.DOCGEN_REPO_ROOT);
  try {
    // execFileSync — no shell, fixed argv. Output is the abs path of the
    // enclosing git worktree (or throws if not in one).
    return execFileSync('git', ['rev-parse', '--show-toplevel'], {
      stdio: ['ignore', 'pipe', 'ignore'],
    })
      .toString()
      .trim();
  } catch {
    return resolve('.');
  }
}

function statePath(root) {
  return join(root, '.docgen', 'state.json');
}

export function loadState(root) {
  const p = statePath(root);
  if (!existsSync(p)) return { version: 1, lastRun: null, directories: {} };
  try {
    const raw = readFileSync(p, 'utf8');
    const parsed = JSON.parse(raw);
    if (parsed && parsed.version === 1 && parsed.directories) return parsed;
  } catch {
    /* fall through */
  }
  return { version: 1, lastRun: null, directories: {} };
}

export function saveState(root, state) {
  const p = statePath(root);
  mkdirSync(dirname(p), { recursive: true });
  // Sort directories for stable diffs.
  const sorted = {
    version: state.version,
    lastRun: state.lastRun,
    directories: Object.fromEntries(
      Object.entries(state.directories).sort(([a], [b]) => a.localeCompare(b)),
    ),
  };
  writeFileSync(p, JSON.stringify(sorted, null, 2) + '\n');
}

/**
 * Serialise concurrent state writes. With `--parallel N` we can have N
 * analyzeOne calls in flight; without this, the LAST writer would lose
 * any entries the others wrote between its loadState and saveState. Each
 * caller appends to a single shared promise chain; the chain's body
 * always re-reads from disk before merging, so two concurrent writers
 * don't clobber each other.
 */
let _saveChain = Promise.resolve();
/** Reset the serialise-writes chain to a clean resolved state. Called
 *  at the top of each top-level run so a chain left pending/poisoned by
 *  a prior run can't stall the next one's first save. */
export function resetSaveChain() { _saveChain = Promise.resolve(); }
export function saveStateMerging(root, additions, lastRun) {
  const apply = () => {
    const state = loadState(root);
    if (lastRun) state.lastRun = lastRun;
    Object.assign(state.directories, additions);
    saveState(root, state);
  };
  // Serialise writes by chaining, but run `apply` whether the previous
  // link resolved OR rejected (`.then(apply, apply)`) so a single
  // failed save can't poison the chain for every future call. The
  // stored chain is also `.catch`-swallowed so it never stays in a
  // rejected state — without this, one thrown save (e.g. a temp root
  // deleted mid-run, as happens between isolated tests) would make
  // every subsequent `await saveStateMerging` reject or stall.
  const result = _saveChain.then(apply, apply);
  _saveChain = result.catch(() => {});
  return result;
}

// ─── directory walking ────────────────────────────────────────────────────

/**
 * Yield directories under root that have at least one regular file OR
 * subdirectories. Trunk directories (only sub-dirs, no files) are
 * included so they can be documented as overview/orchestration layers
 * once their children have READMEs; they would otherwise have no entry
 * point for an agent navigating top-down.
 *
 * Skips SKIP_DIRS at any depth and hidden directories.
 */
export function* walkDirs(root) {
  const stack = [root];
  while (stack.length > 0) {
    const dir = stack.pop();
    let entries;
    try {
      entries = readdirSync(dir, { withFileTypes: true });
    } catch {
      continue;
    }
    const subdirs = [];
    let hasFiles = false;
    let hasUsableSubdirs = false;
    for (const e of entries) {
      if (e.name === '.' || e.name === '..') continue;
      // Hidden dirs (except .github which often has CI we care about).
      if (e.name.startsWith('.') && e.name !== '.github') continue;
      if (SKIP_DIRS.has(e.name)) continue;
      if (e.isDirectory()) {
        subdirs.push(join(dir, e.name));
        hasUsableSubdirs = true;
      } else if (e.isFile()) hasFiles = true;
    }
    if (hasFiles || hasUsableSubdirs) yield dir;
    // Reverse so depth-first order matches lexical order on output.
    for (let i = subdirs.length - 1; i >= 0; i--) stack.push(subdirs[i]);
  }
}

/** Pick the files in `dir` we'll feed to claude. Sorted by name for
 *  deterministic prompts. */
export function selectFiles(dir) {
  const out = [];
  let entries;
  try {
    entries = readdirSync(dir, { withFileTypes: true });
  } catch {
    return out;
  }
  for (const e of entries) {
    if (!e.isFile()) continue;
    // We OWN README.md — don't feed our own output back in.
    if (e.name === 'README.md') continue;
    if (SKIP_FILE_EXT.has(extname(e.name).toLowerCase())) continue;
    if (e.name.startsWith('.')) continue;
    const full = join(dir, e.name);
    let st;
    try {
      st = statSync(full);
    } catch {
      continue;
    }
    if (st.size > MAX_FILE_BYTES_HARD) continue;
    out.push({ name: e.name, full, mtimeMs: st.mtimeMs, size: st.size });
  }
  out.sort((a, b) => a.name.localeCompare(b.name));
  return out;
}

/**
 * walkDirs sorted by depth descending (deepest first), with lexical
 * secondary order. Bottom-up traversal lets us generate child READMEs
 * before parents that summarise them, which is the entire point of the
 * pyramid: a parent's prompt context can include its children's
 * already-generated READMEs (one paragraph each) instead of the
 * children's raw files (kilobytes each).
 */
export function walkDirsBottomUp(root) {
  const all = [...walkDirs(root)];
  return all.sort((a, b) => {
    const depthDiff = b.split('/').length - a.split('/').length;
    return depthDiff !== 0 ? depthDiff : a.localeCompare(b);
  });
}

/**
 * Find immediate sub-directories of `dir` that already have a generated
 * README + version in state. Returned list is what feeds the "you are a
 * trunk; summarise these children" prompt context.
 */
export function findChildReadmesInState(root, dir, state) {
  let entries;
  try {
    entries = readdirSync(dir, { withFileTypes: true });
  } catch {
    return [];
  }
  const out = [];
  for (const e of entries) {
    if (!e.isDirectory()) continue;
    if (e.name.startsWith('.') && e.name !== '.github') continue;
    if (SKIP_DIRS.has(e.name)) continue;
    const subFull = join(dir, e.name);
    const subRel = relative(root, subFull);
    const subEntry = state.directories[subRel];
    if (!subEntry?.version) continue;
    const subReadmePath = join(subFull, 'README.md');
    if (!existsSync(subReadmePath)) continue;
    try {
      out.push({
        relPath: subRel,
        version: subEntry.version,
        content: readFileSync(subReadmePath, 'utf8'),
      });
    } catch { /* ignore */ }
  }
  out.sort((a, b) => a.relPath.localeCompare(b.relPath));
  return out;
}

// ─── hand-written README protection ──────────────────────────────────────

/**
 * Was this README hand-written? A README that exists but does NOT carry
 * the auto-gen marker is treated as load-bearing prose owned by a human
 * (or by a previous Claude session that hand-wrote it as a spec) —
 * docgen MUST NOT overwrite it.
 *
 * The repo root README and several subsystem READMEs (bots/, lab/,
 * tools/docgen/) are deliberately hand-tuned for new-user onboarding;
 * running docgen without this guard would replace them with generated
 * prose and silently lose that work.
 *
 * Override via `analyzeOne({ force: true })` / `docgen --force` if you
 * REALLY want to replace a hand-written README — explicit opt-in only.
 */
export function isHandWrittenReadme(readmePath) {
  if (!existsSync(readmePath)) return false;
  try {
    const head = readFileSync(readmePath, 'utf8').slice(0, 512);
    return !head.trimStart().startsWith(MARKER_DETECT_PREFIX);
  } catch {
    // Unreadable file — treat as hand-written so we don't clobber it.
    return true;
  }
}

// ─── version handling (semver-flavoured) ──────────────────────────────────

const VERSION_RE = /<!--\s*docgen:version=(\d+)\.(\d+)\.(\d+)(?:\s+reason:\s*([^>]*?))?\s*-->/;

/**
 * Parse `<!-- docgen:version=X.Y.Z reason: ... -->` out of a string.
 * Returns `{ version, reason, raw }` or `null` if not found.
 */
export function parseVersion(text) {
  if (!text) return null;
  const m = (text || '').match(VERSION_RE);
  if (!m) return null;
  return {
    version: `${m[1]}.${m[2]}.${m[3]}`,
    reason: (m[4] ?? '').trim() || null,
    raw: m[0],
  };
}

/** Read prior version from `<dir>/README.md` (if any). */
export function priorVersion(dir) {
  const p = join(dir, 'README.md');
  if (!existsSync(p)) return null;
  try {
    const head = readFileSync(p, 'utf8').slice(0, 2 * 1024);
    return parseVersion(head)?.version ?? null;
  } catch {
    return null;
  }
}

/**
 * Classify a version transition as patch/minor/major/same/initial.
 * Compares `prev` to `next` ; either may be null/undefined.
 */
export function bumpType(prev, next) {
  if (!prev && next) return 'initial';
  if (!prev && !next) return 'initial';
  if (!next) return 'same';
  const [pM, pm, pp] = prev.split('.').map(Number);
  const [nM, nm, np] = next.split('.').map(Number);
  if (nM !== pM) return 'major';
  if (nm !== pm) return 'minor';
  if (np !== pp) return 'patch';
  return 'same';
}

/**
 * Resolve the final version to write. Inputs:
 *   - priorV: version of the prior README (or null)
 *   - llmV: version the LLM declared in its output (or null)
 *   - fileSetChanged: whether files were added/removed since priorV
 *
 * Policy:
 *   - If no prior, accept LLM's declared version, defaulting to '0.1.0'.
 *   - If LLM didn't declare a version, fall back to a patch bump.
 *   - If the LLM declared a patch bump BUT files were added/removed,
 *     escalate to minor — the LLM's judgement is overridable here so a
 *     genuine structural change can't be silently labelled cosmetic.
 *   - Otherwise honour the LLM's version.
 */
export function resolveVersion(priorV, llmV, fileSetChanged) {
  if (!priorV) return llmV ?? '0.1.0';
  if (!llmV) {
    const [M, m, p] = priorV.split('.').map(Number);
    return `${M}.${m}.${p + 1}`;
  }
  if (fileSetChanged && bumpType(priorV, llmV) === 'patch') {
    const [M, m] = priorV.split('.').map(Number);
    return `${M}.${m + 1}.0`;
  }
  return llmV;
}

// ─── staleness ────────────────────────────────────────────────────────────

/**
 * Reason a directory needs (re)analysis, or null if fresh. Three kinds
 * of staleness:
 *   - own file-set / mtime drift (this dir's own files changed),
 *   - child README crossed a minor-or-major boundary since we last
 *     looked (a sub-directory's responsibilities materially changed),
 *   - a new child README appeared that wasn't there when we were last
 *     analysed (new sub-directory landed under us).
 *
 * Pure cosmetic (patch) bumps in children DO NOT propagate. That's the
 * cost optimisation; without it, one leaf edit re-generates every
 * ancestor up to the repo root.
 */
export function needsAnalysis(root, dir, state) {
  const rel = relative(root, dir) || '.';
  const entry = state.directories[rel];
  const files = selectFiles(dir);
  const childReadmes = findChildReadmesInState(root, dir, state);
  // Nothing to document — no own files, no documented children.
  if (files.length === 0 && childReadmes.length === 0) return null;
  if (files.length > MAX_FILES_PER_DIR) return null; // generated/asset dir
  // Protected: existing README is hand-written. Skip silently from the
  // automatic walk; users wanting to convert can pass `--force --dir`.
  if (isHandWrittenReadme(join(dir, 'README.md'))) return null;
  if (!entry) return 'never-analyzed';

  // Own-file checks.
  const prev = entry.files || {};
  const curNames = files.map((f) => f.name).sort();
  const prevNames = Object.keys(prev).sort();
  if (curNames.length !== prevNames.length) return 'file-set-changed';
  for (let i = 0; i < curNames.length; i++) {
    if (curNames[i] !== prevNames[i]) return 'file-set-changed';
  }
  for (const f of files) {
    if (Math.floor(prev[f.name] ?? 0) !== Math.floor(f.mtimeMs)) {
      return 'file-modified';
    }
  }

  // Child-version checks. Compare major.minor only — patch bumps in
  // children are deliberately ignored.
  const recordedChildren = entry.childVersionsAtAnalysis || {};
  for (const c of childReadmes) {
    const recorded = recordedChildren[c.relPath];
    if (!recorded) return `child-added:${c.relPath}`;
    const [rM, rm] = recorded.split('.').map(Number);
    const [cM, cm] = c.version.split('.').map(Number);
    if (rM !== cM || rm !== cm) return `child-bumped:${c.relPath}`;
  }
  // A child we previously summarised has disappeared (dir removed).
  for (const recordedRel of Object.keys(recordedChildren)) {
    if (!childReadmes.some((c) => c.relPath === recordedRel)) {
      return `child-removed:${recordedRel}`;
    }
  }

  // Curated-context file checks. Any new file, mtime bump, or removed
  // file triggers a re-generation. Same semantic as own-files: if the
  // input to the prompt changed, the output is stale.
  const recordedCtx = entry.curatedContextAtAnalysis || {};
  const currentCtx = collectCuratedContext(root, dir);
  for (const c of currentCtx) {
    const recorded = recordedCtx[c.relPath];
    if (recorded === undefined) return `context-added:${c.relPath}`;
    if (Math.floor(recorded) !== Math.floor(c.mtimeMs)) {
      return `context-modified:${c.relPath}`;
    }
  }
  for (const recordedRel of Object.keys(recordedCtx)) {
    if (!currentCtx.some((c) => c.relPath === recordedRel)) {
      return `context-removed:${recordedRel}`;
    }
  }
  return null;
}

// ─── claude subprocess ────────────────────────────────────────────────────

/** Default claude runner. Pass a mock via `analyzeOne({ runner })` in
 *  tests. spawn() with array args — no shell interpolation. */
function defaultRunner({ prompt, context, model, timeoutMs = DEFAULT_TIMEOUT_MS }) {
  return new Promise((resolveP, rejectP) => {
    const args = ['-p', '--output-format', 'text'];
    if (model) args.push('--model', model);
    const proc = spawn('claude', args, { stdio: ['pipe', 'pipe', 'pipe'] });
    let stdout = '';
    let stderr = '';
    let settled = false;
    const settle = (fn) => {
      if (!settled) {
        settled = true;
        fn();
      }
    };
    const timer = setTimeout(() => {
      try { proc.kill('SIGTERM'); } catch { /* gone */ }
      settle(() => rejectP(new Error(`docgen: claude timed out after ${timeoutMs}ms`)));
    }, timeoutMs);
    proc.stdout.on('data', (d) => (stdout += d.toString()));
    proc.stderr.on('data', (d) => (stderr += d.toString()));
    proc.on('error', (err) => {
      clearTimeout(timer);
      settle(() => rejectP(new Error(
        err.code === 'ENOENT'
          ? 'docgen: claude CLI not on PATH — install with: npm install -g @anthropic-ai/claude-code'
          : `docgen: claude spawn error: ${err.message}`,
      )));
    });
    proc.on('exit', (code) => {
      clearTimeout(timer);
      settle(() => {
        if (code === 0) { resolveP(stdout); return; }
        const err = new Error(`docgen: claude exited ${code}: ${stderr.slice(0, 500)}`);
        // Detect the "current working directory was deleted" failure
        // — claude itself checks its own cwd before running and bails.
        // When this fires, EVERY subsequent call from --until-done will
        // also fail the same way, so flag it as fatal so the outer
        // loop halts instead of retrying forever (the runaway-zombie
        // class of bug). See checkAbortCwdDeleted in analyzeAllParallel.
        if (/current working directory was deleted|cwd .* deleted/i.test(stderr)) {
          err.code = 'CWD_DELETED';
          err.halt = true;
        }
        rejectP(err);
      });
    });
    proc.stdin.on('error', () => {});
    try {
      proc.stdin.write(prompt + '\n\n--- CONTEXT ---\n\n' + context);
      proc.stdin.end();
    } catch {
      /* error/exit will reject */
    }
  });
}

// ─── prompt assembly ──────────────────────────────────────────────────────

function loadPrompt(scriptDir) {
  return readFileSync(join(scriptDir, 'prompt.md'), 'utf8');
}

/**
 * Assemble the context string the LLM sees: a header naming the dir,
 * the prior version (if any), the parent README (for vocabulary),
 * any already-generated child READMEs (for trunk dirs — these turn
 * the LLM into a summariser, not a re-grepper), and every selected
 * file as a fenced block. Files over the per-file cap are truncated.
 */
/**
 * Collect curated-context items for a directory's prompt. Returns an
 * array of `{label, content, relPath, mtimeMs}` in priority order:
 *
 *   1. Global  — `<root>/.docgen/global.md` (every prompt)
 *   2. Local   — `<dir>/.docgen-context.md` (only this dir's prompt)
 *   3. Cascade — every `<descendant>/.docgen-cascade.md` (bubbles up)
 *
 * The bubble-up pattern is the load-bearing one: a single
 * `.docgen-cascade.md` at `bots/scripts/backtest/factory/` (e.g.
 * "available commands at this layer") flows into the prompts of
 * every ancestor (`backtest/`, `scripts/`, `bots/`, `.`), so the
 * generated README at each level naturally surfaces the same vocab.
 *
 * Each entry's `relPath` + `mtimeMs` is also persisted into state so
 * `needsAnalysis` can re-trigger a re-generation when a context file
 * changes — same shape as the existing per-file mtime tracking.
 */
export function collectCuratedContext(root, dir) {
  const items = [];

  const globalPath = join(root, CTX_GLOBAL_PATH);
  if (existsSync(globalPath)) {
    items.push({
      label: 'Global context (.docgen/global.md)',
      content: readFileSync(globalPath, 'utf8').slice(0, MAX_CTX_BYTES),
      relPath: relative(root, globalPath),
      mtimeMs: statSync(globalPath).mtimeMs,
    });
  }

  const localPath = join(dir, CTX_LOCAL_FILENAME);
  if (existsSync(localPath)) {
    items.push({
      label: `Local context (${relative(root, localPath)})`,
      content: readFileSync(localPath, 'utf8').slice(0, MAX_CTX_BYTES),
      relPath: relative(root, localPath),
      mtimeMs: statSync(localPath).mtimeMs,
    });
  }

  // Cascade: every descendant's .docgen-cascade.md bubbles into this
  // dir's prompt. Reuses walkDirs so we get the same SKIP_DIRS filter
  // (no node_modules, no .git, etc.).
  for (const descendant of walkDirs(dir)) {
    const cascadePath = join(descendant, CTX_CASCADE_FILENAME);
    if (!existsSync(cascadePath)) continue;
    items.push({
      label: `Cascade context (${relative(root, cascadePath)})`,
      content: readFileSync(cascadePath, 'utf8').slice(0, MAX_CTX_BYTES),
      relPath: relative(root, cascadePath),
      mtimeMs: statSync(cascadePath).mtimeMs,
    });
  }

  return items;
}

export function assembleContext(root, dir, files, opts = {}) {
  const { childReadmes = [], priorVersionStr = null, curatedContext = [] } = opts;
  const rel = relative(root, dir) || '.';
  const lines = [`# Directory: ${rel}`, ''];

  if (priorVersionStr) {
    lines.push(`## Prior version of this README`);
    lines.push('');
    lines.push(`The previous README declared version \`${priorVersionStr}\`.`);
    lines.push(
      'Bump patch / minor / major versus this baseline per the rules in your instructions.',
    );
    lines.push('');
  } else {
    lines.push('## Prior version of this README');
    lines.push('');
    lines.push('No prior README — this is the first generation. Start at `0.1.0`.');
    lines.push('');
  }

  // Curated context — hand-written guidance the maintainer wants the
  // LLM to treat as authoritative when generating this README. Pulled
  // from three locations (see collectCuratedContext):
  //   .docgen/global.md            — applies to every dir's prompt
  //   <dir>/.docgen-context.md     — only this dir's prompt
  //   <descendant>/.docgen-cascade.md — bubbles up into every ancestor's
  //                                     prompt (use for "available
  //                                     commands at this layer" etc)
  // Comes BEFORE child READMEs + raw files so the LLM frames the
  // generated content around the maintainer's intent rather than
  // re-deriving from scratch.
  if (curatedContext.length > 0) {
    lines.push('## Curated context (hand-written, treat as authoritative)');
    lines.push('');
    for (const item of curatedContext) {
      lines.push(`### ${item.label}`);
      lines.push('');
      lines.push(item.content.trimEnd());
      lines.push('');
    }
  }

  // Parent README for vocabulary continuity.
  const parentReadme = join(dirname(dir), 'README.md');
  if (parentReadme !== join(dir, 'README.md') && existsSync(parentReadme)) {
    try {
      const txt = readFileSync(parentReadme, 'utf8');
      lines.push(`## Parent directory README (for context only)`);
      lines.push('');
      lines.push(txt.slice(0, 4 * 1024));
      lines.push('');
    } catch { /* ignore */ }
  }

  // Child READMEs — present iff this is a trunk dir. The LLM
  // SUMMARISES these in the new ## Subdirectories section; it does NOT
  // re-derive their detail from raw files.
  if (childReadmes.length > 0) {
    lines.push(
      `## Already-generated child READMEs (${childReadmes.length}) — summarise, do NOT duplicate`,
    );
    lines.push('');
    for (const c of childReadmes) {
      lines.push(`### Subdirectory: ${c.relPath}  (version ${c.version})`);
      lines.push('');
      lines.push(c.content.slice(0, 4 * 1024));
      lines.push('');
    }
  }

  lines.push(`## Files directly in this directory (${files.length})`);
  lines.push('');
  for (const f of files) {
    let body;
    try {
      body = readFileSync(f.full, 'utf8');
    } catch {
      continue;
    }
    let truncated = false;
    if (body.length > MAX_FILE_BYTES_FOR_PROMPT) {
      body = body.slice(0, MAX_FILE_BYTES_FOR_PROMPT);
      truncated = true;
    }
    const ext = extname(f.name).slice(1) || '';
    lines.push(`### ${f.name}${truncated ? ' (truncated)' : ''}`);
    lines.push('```' + ext);
    lines.push(body.trimEnd());
    lines.push('```');
    lines.push('');
  }
  return lines.join('\n');
}

// ─── analysis core ────────────────────────────────────────────────────────

/** Inspect the user's local clone for our pre-push hook. Returns
 *  `{installed: bool, reason: string}` — `reason` explains the
 *  specific gap so the status output can be actionable rather than
 *  just "not installed."
 *
 *  Three install layouts to recognise:
 *    1. .git/hooks/pre-push                   — vanilla install
 *    2. <core.hooksPath>/pre-push             — shared hooks dir
 *    3. .git/hooks/pre-push-local             — chained alongside
 *                                                another global hook
 *                                                (e.g. an identity
 *                                                guard) that exec's
 *                                                pre-push-local at end
 *  Any one being present + executable + carrying our MARKER counts.
 */
function checkPreHookInstalled(root) {
  const MARKER = 'DOCGEN_PRE_PUSH_HOOK_v1';
  const gitDirRaw = (() => {
    try {
      return execFileSync('git', ['rev-parse', '--git-dir'], {
        cwd: root, encoding: 'utf8',
      }).trim();
    } catch { return null; }
  })();
  if (!gitDirRaw) return { installed: false, reason: 'not in a git repo' };
  const gitDir = resolve(root, gitDirRaw);
  const hooksPath = (() => {
    try {
      const p = execFileSync('git', ['config', 'core.hooksPath'], {
        cwd: root, encoding: 'utf8',
      }).trim();
      return p ? resolve(root, p) : null;
    } catch { return null; }
  })();
  const candidates = [
    join(gitDir, 'hooks', 'pre-push'),
    join(gitDir, 'hooks', 'pre-push-local'),
    ...(hooksPath ? [join(hooksPath, 'pre-push'), join(hooksPath, 'pre-push-local')] : []),
  ];
  for (const path of candidates) {
    if (!existsSync(path)) continue;
    try {
      const content = readFileSync(path, 'utf8');
      if (content.includes(MARKER)) return { installed: true, reason: `via ${relative(root, path)}` };
    } catch { /* skip */ }
  }
  return {
    installed: false,
    reason: 'no pre-push file carries the docgen marker (DOCGEN_PRE_PUSH_HOOK_v1)',
  };
}

/** True when the failure looks like "the file/dir we're operating on
 *  vanished" — covers the short-lived-worktree cleanup race that
 *  hits when another tool spawns + tears down a temp clone faster
 *  than the detached docgen background process can finish. */
function isVanishedPathError(err) {
  if (!err || typeof err !== 'object') return false;
  return err.code === 'ENOENT' || err.code === 'ENOTDIR' || err.code === 'EACCES';
}

export async function analyzeOne(root, opts = {}) {
  const {
    runner = defaultRunner,
    promptText,
    forceDir = null,
    force = false,
    model,
    timeoutMs,
    dryRun = false,
  } = opts;

  const state = loadState(root);

  // Pick the target. Bottom-up walk so a leaf is documented before its
  // trunk — that way the trunk's prompt gets the children's already-
  // generated READMEs as context instead of re-deriving from raw files.
  let target = null;
  let reason = null;
  if (forceDir) {
    target = resolve(forceDir);
    reason = 'forced';
  } else {
    for (const dir of walkDirsBottomUp(root)) {
      const r = needsAnalysis(root, dir, state);
      if (r) {
        target = dir;
        reason = r;
        break;
      }
    }
  }
  if (!target) return { picked: null };

  // Defensive: the target dir may have vanished between when the walk
  // picked it and when we run. Two ways this happens in practice:
  //   1) Worktree cleanup race — another tool spawns a short-lived
  //      worktree, kicks the pre-push hook, then deletes the worktree
  //      before our detached background process finishes.
  //   2) The directory was committed away (refactor moved it) between
  //      state-load and now in --until-done.
  // In either case, skip cleanly so the BATCH keeps making progress on
  // the other dirs. The state entry stays as-is; next run notices and
  // re-routes.
  if (!existsSync(target)) {
    return {
      picked: relative(root, target) || '.',
      skipped: 'vanished',
      message: `target directory no longer exists (worktree cleanup race?); skipping`,
    };
  }

  const files = selectFiles(target);
  const childReadmes = findChildReadmesInState(root, target, state);
  if (files.length === 0 && childReadmes.length === 0) return { picked: null };

  const rel = relative(root, target) || '.';
  const readmePath = join(target, 'README.md');

  // Defensive: refuse to overwrite a hand-written README unless the
  // caller explicitly opted in via `--force`. The needsAnalysis filter
  // already excludes these from the automatic walk, but `--dir <path>`
  // bypasses that, so this is the catch-net.
  if (!force && isHandWrittenReadme(readmePath)) {
    return {
      picked: rel,
      skipped: 'hand-written-readme',
      readmePath,
      message:
        `README.md in ${rel} is hand-written (no docgen marker). ` +
        `Refusing to overwrite. Use --force to deliberately convert it.`,
    };
  }

  const priorV = priorVersion(target);
  const curatedContext = collectCuratedContext(root, target);
  const context = assembleContext(root, target, files, {
    childReadmes,
    priorVersionStr: priorV,
    curatedContext,
  });

  if (dryRun) {
    return {
      picked: rel,
      reason,
      fileCount: files.length,
      childCount: childReadmes.length,
      priorVersion: priorV,
      dryRun: true,
    };
  }

  const body = await runner({
    prompt: promptText,
    context,
    model,
    timeoutMs,
  });

  // Strip outer ```markdown fence if Claude wrapped its response.
  const cleaned = stripWrappingFence(body).trim();

  // Extract the LLM's declared version, then resolve to the final
  // version we'll write. The LLM's choice may be overridden if the
  // file-set changed but the LLM picked patch (see resolveVersion).
  const llmVersion = parseVersion(cleaned)?.version ?? null;
  const fileSetChanged = computeFileSetChanged(state, rel, files);
  const finalVersion = resolveVersion(priorV, llmVersion, fileSetChanged);

  // Build the on-disk content: docgen MARKER, then a normalised
  // version line (regardless of what the LLM emitted — we own this),
  // then the LLM's body with its own version line stripped out so we
  // don't end up with two version lines stacked.
  const versionReason =
    parseVersion(cleaned)?.reason ?? (priorV ? 'auto-generated' : 'initial generation');
  const normalisedVersionLine =
    `<!-- docgen:version=${finalVersion} reason: ${versionReason} -->`;
  const bodyWithoutVersion = cleaned.replace(VERSION_RE, '').replace(/^\s+/, '');
  const finalContent = `${MARKER}\n${normalisedVersionLine}\n\n${bodyWithoutVersion}\n`;

  // Ensure the parent dir still exists (mkdirp) — if the worktree was
  // partially cleaned mid-flight the leaf dir may be gone even though
  // the existsSync check above passed when we started. mkdirSync with
  // recursive:true is a no-op when the dir already exists.
  try {
    mkdirSync(dirname(readmePath), { recursive: true });
    writeFileSync(readmePath, finalContent);
  } catch (err) {
    if (isVanishedPathError(err)) {
      return {
        picked: rel,
        skipped: 'vanished',
        message: `path no longer writable (${err.code}); worktree likely cleaned mid-run`,
      };
    }
    throw err;
  }

  // Persist via the merging save so concurrent analyzeOne calls (with
  // `--parallel N`) don't clobber each other's entries. saveStateMerging
  // re-reads from disk inside its mutex, merges our additions, and
  // writes back.
  const newEntry = {
    lastAnalyzed: new Date().toISOString(),
    reason,
    version: finalVersion,
    files: Object.fromEntries(files.map((f) => [f.name, Math.floor(f.mtimeMs)])),
    childVersionsAtAnalysis: Object.fromEntries(
      childReadmes.map((c) => [c.relPath, c.version]),
    ),
    // Track the curated-context files we read so needsAnalysis can
    // re-trigger when any of them changes (added, mtime bumped, or
    // removed entirely).
    curatedContextAtAnalysis: Object.fromEntries(
      curatedContext.map((c) => [c.relPath, Math.floor(c.mtimeMs)]),
    ),
  };
  await saveStateMerging(root, { [rel]: newEntry }, new Date().toISOString());

  return {
    picked: rel,
    reason,
    fileCount: files.length,
    childCount: childReadmes.length,
    priorVersion: priorV,
    llmVersion,
    finalVersion,
    fileSetChanged,
    readmePath,
    bytes: finalContent.length,
  };
}

/** Did the file set in `rel` change vs what state recorded? */
function computeFileSetChanged(state, rel, files) {
  const entry = state.directories[rel];
  if (!entry) return false; // first analysis — not a "change"
  const prev = entry.files || {};
  const curNames = files.map((f) => f.name).sort();
  const prevNames = Object.keys(prev).sort();
  if (curNames.length !== prevNames.length) return true;
  for (let i = 0; i < curNames.length; i++) {
    if (curNames[i] !== prevNames[i]) return true;
  }
  return false;
}

/** If Claude wrapped its response in a single outer ```markdown fence,
 *  strip it. Otherwise return as-is. */
function stripWrappingFence(s) {
  const trimmed = s.trim();
  const m = trimmed.match(/^```(?:markdown|md)?\s*\n([\s\S]*?)\n```\s*$/);
  return m ? m[1] : trimmed;
}

// ─── parallel orchestrator ────────────────────────────────────────────────

/**
 * Run docgen across every needs-analysis directory, parallelising
 * within depth levels. Bottom-up ordering is preserved (a trunk's
 * children are always documented first); only DIRS AT THE SAME DEPTH
 * run concurrently, because they are guaranteed to be independent —
 * siblings or unrelated branches whose subtrees were already settled
 * in earlier iterations.
 *
 * Concurrency cap: at most `parallel` analyzeOne calls in flight at
 * once, regardless of how many actionable dirs share a depth.
 *
 * Progress: `onProgress(result)` fires once per completed dir. The
 * CLI uses this to print "[N/total] wrote bots/src/server (..)" lines
 * so a tail -f or Monitor can follow the bootstrap live.
 */
export async function analyzeAllParallel(root, opts = {}) {
  const {
    parallel = 1,
    onProgress,
    onBatchStart,
    ...analyzeOpts
  } = opts;

  // Reset the module-global save-chain at the start of every top-level
  // run. Without this, a chain left in a pending/poisoned state by a
  // prior run (or a prior test in the same process) would make the
  // first saveStateMerging here await a `.then` that never fires —
  // a silent hang. A fresh run owns a fresh chain.
  resetSaveChain();

  let done = 0;
  let skipped = 0;

  // Outer loop: each iteration handles ONE depth level. We re-walk the
  // tree each time so freshly-written child READMEs become visible to
  // trunk-staleness checks for the next iteration.
  for (;;) {
    const state = loadState(root);
    const actionable = [];
    for (const dir of walkDirs(root)) {
      const reason = needsAnalysis(root, dir, state);
      if (reason) actionable.push({ dir, reason });
    }
    if (actionable.length === 0) break;

    // Restrict this batch to the deepest depth. Shallower dirs wait
    // for their children to finish on a future iteration.
    const depths = actionable.map((a) => a.dir.split('/').length);
    const maxDepth = Math.max(...depths);
    const sameDepth = actionable.filter(
      (a) => a.dir.split('/').length === maxDepth,
    );

    // Process the depth group in chunks of `parallel`. Within a chunk,
    // Promise.allSettled fans out; chunks themselves are serialised so
    // we never have more than `parallel` calls running. allSettled
    // (vs all) is load-bearing: if one analyzeOne throws for one dir
    // — a network blip on `claude -p`, a vanished worktree, etc. —
    // the OTHER concurrent dirs in the same chunk should still land
    // their READMEs instead of being silently discarded.
    for (let i = 0; i < sameDepth.length; i += parallel) {
      const chunk = sameDepth.slice(i, i + parallel);
      onBatchStart?.({ depth: maxDepth, chunkSize: chunk.length });
      const settled = await Promise.allSettled(
        chunk.map((b) =>
          analyzeOne(root, { ...analyzeOpts, forceDir: b.dir }),
        ),
      );
      let halt = false;
      for (let j = 0; j < settled.length; j++) {
        const s = settled[j];
        if (s.status === 'fulfilled') {
          const r = s.value;
          if (r.skipped) skipped++;
          else if (r.picked) done++;
          onProgress?.(r);
        } else {
          // Surface as a skip with the error message so the operator
          // sees what failed without the whole batch tearing down.
          skipped++;
          onProgress?.({
            picked: chunk[j].dir,
            skipped: 'error',
            message: s.reason?.message ?? String(s.reason),
          });
          // Detect the "cwd was deleted" fatal — every subsequent
          // dir would fail the same way (worktree is gone). Bail the
          // outer loop instead of grinding forever.
          if (s.reason?.halt || s.reason?.code === 'CWD_DELETED') halt = true;
        }
      }
      if (halt) {
        onProgress?.({
          picked: '<batch>',
          skipped: 'halt',
          message: 'cwd deleted (worktree cleanup); halting --until-done loop',
        });
        return { done, skipped, halted: true };
      }
    }
  }

  return { done, skipped };
}

// ─── status reporting ─────────────────────────────────────────────────────

export function computeStatus(root) {
  const state = loadState(root);
  const dirs = [];
  for (const dir of walkDirs(root)) {
    const rel = relative(root, dir) || '.';
    const entry = state.directories[rel];
    const reason = needsAnalysis(root, dir, state);
    const protectedHandwritten = isHandWrittenReadme(join(dir, 'README.md'));
    dirs.push({
      dir: rel,
      analyzed: !!entry,
      lastAnalyzed: entry?.lastAnalyzed ?? null,
      needsReanalysis: reason,
      protected: protectedHandwritten,
    });
  }
  const total = dirs.length;
  const protectedCount = dirs.filter((d) => d.protected).length;
  // "Documented" only counts auto-gen READMEs that are fresh; protected
  // hand-written READMEs are tracked separately so the bootstrap
  // progress meter isn't inflated by files docgen didn't author.
  const documented = dirs.filter(
    (d) => d.analyzed && !d.needsReanalysis && !d.protected,
  ).length;
  const stale = dirs.filter((d) => d.analyzed && d.needsReanalysis).length;
  const uncovered = dirs.filter(
    (d) => !d.analyzed && !d.protected,
  ).length;
  return { total, documented, stale, uncovered, protected: protectedCount, dirs };
}

// ─── CLI ──────────────────────────────────────────────────────────────────

function parseArgs(argv) {
  const out = { positional: [], flags: {} };
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === '--until-done') out.flags.untilDone = true;
    else if (a === '--dry-run') out.flags.dryRun = true;
    else if (a === '--force') out.flags.force = true;
    else if (a === '--help' || a === '-h') out.flags.help = true;
    else if (a === '--dir') out.flags.dir = argv[++i];
    else if (a === '--model') out.flags.model = argv[++i];
    else if (a === '--timeout-ms') out.flags.timeoutMs = Number(argv[++i]);
    else if (a === '--parallel') out.flags.parallel = Math.max(1, Number(argv[++i]) || 1);
    else out.positional.push(a);
  }
  return out;
}

function printHelp() {
  // Header comment at top of file is the spec.
  const here = fileURLToPath(new URL('.', import.meta.url));
  const self = join(here, 'docgen.mjs');
  const lines = readFileSync(self, 'utf8').split('\n');
  const start = lines.findIndex((l) => l.startsWith('/**'));
  const end = lines.findIndex((l, i) => i > start && l.includes('*/'));
  if (start < 0 || end < 0) {
    console.log('docgen — see header of docgen.mjs');
    return;
  }
  for (const l of lines.slice(start + 1, end)) {
    console.log(l.replace(/^ \* ?/, ''));
  }
}

async function main() {
  const args = parseArgs(process.argv.slice(2));
  if (args.flags.help) { printHelp(); return; }
  const sub = args.positional[0];
  const root = repoRoot();

  if (sub === 'status') {
    const s = computeStatus(root);
    const docTarget = s.total - s.protected;
    const pct = docTarget === 0 ? 0 : ((s.documented / docTarget) * 100).toFixed(1);
    console.log(`docgen status — ${s.documented}/${docTarget} dirs documented (${pct}%)`);
    console.log(`  stale (needs re-analysis): ${s.stale}`);
    console.log(`  uncovered (never analyzed): ${s.uncovered}`);
    console.log(`  protected (hand-written, skipped): ${s.protected}`);
    const todo = s.dirs
      .filter((d) => !d.protected && (!d.analyzed || d.needsReanalysis))
      .slice(0, 15);
    if (todo.length) {
      console.log('  next 15 todo:');
      for (const d of todo) {
        const reason = d.needsReanalysis ?? 'never-analyzed';
        console.log(`    - ${d.dir}  (${reason})`);
      }
    }
    if (s.protected > 0) {
      const examples = s.dirs.filter((d) => d.protected).slice(0, 8);
      console.log('  protected (sample):');
      for (const d of examples) console.log(`    - ${d.dir}/README.md`);
      console.log('  (use --force --dir <path> to deliberately convert a hand-written README)');
    }
    // Hook-install check. Auto-refresh ONLY happens when the pre-push
    // hook is installed on this clone — git hooks aren't versioned, so
    // every fresh clone starts without one. Surface it loudly here so
    // operators notice instead of silently shipping drift on PR
    // pushes from un-installed clones.
    const hookState = checkPreHookInstalled(root);
    if (!hookState.installed) {
      console.log('');
      console.log('  ⚠ pre-push hook NOT installed on this clone — auto-refresh will not fire');
      console.log(`    reason: ${hookState.reason}`);
      console.log('    install: ./tools/docgen/install-push-hook.sh');
    }
    return;
  }

  const here = dirname(fileURLToPath(import.meta.url));
  const promptText = loadPrompt(here);

  const runOpts = {
    promptText,
    forceDir: args.flags.dir,
    force: !!args.flags.force,
    model: args.flags.model,
    timeoutMs: args.flags.timeoutMs ?? DEFAULT_TIMEOUT_MS,
    dryRun: args.flags.dryRun,
  };

  if (args.flags.untilDone) {
    // Sanity check before entering the loop — if our cwd is already
    // gone (parent automation deleted the worktree before we got
    // here), bail cleanly. Saves spawning a claude subprocess that
    // would only return "cwd deleted" itself.
    try { process.cwd(); } catch {
      console.log('docgen: cwd no longer exists — refusing to enter --until-done loop');
      process.exit(0);
    }
    // When --dir is set alongside --until-done, fall through to the
    // single-shot path. That's the explicit "force one target, no loop"
    // contract; --parallel doesn't apply to a single target.
    if (args.flags.dir) {
      const res = await analyzeOne(root, runOpts);
      if (!res.picked) {
        console.log('docgen: nothing to do.');
      } else if (res.skipped) {
        console.log(`docgen: SKIP ${res.picked} — ${res.message}`);
      } else {
        console.log(`docgen: ${res.dryRun ? 'DRY' : 'wrote'} ${res.picked} (${res.reason})`);
      }
      return;
    }
    const parallel = args.flags.parallel ?? 1;
    let count = 0;
    const t0 = Date.now();
    const { done, skipped } = await analyzeAllParallel(root, {
      ...runOpts,
      parallel,
      onBatchStart: ({ depth, chunkSize }) => {
        console.log(`docgen: → batch at depth ${depth} (${chunkSize} in parallel)`);
      },
      onProgress: (res) => {
        if (res.skipped) {
          console.log(`docgen: SKIP ${res.picked} — ${res.message}`);
          return;
        }
        count++;
        const elapsed = ((Date.now() - t0) / 1000).toFixed(0);
        console.log(
          `docgen: [${count}] ${res.dryRun ? 'DRY' : 'wrote'} ${res.picked}` +
            ` (${res.reason}, v${res.finalVersion ?? '-'}, ${res.fileCount}f` +
            (res.childCount ? `+${res.childCount}c` : '') +
            `, ${elapsed}s elapsed)`,
        );
      },
    });
    const wall = ((Date.now() - t0) / 1000).toFixed(0);
    console.log(
      `docgen: done. ${done} dirs processed${skipped ? `, ${skipped} skipped` : ''}, ${wall}s wall-clock, parallel=${parallel}.`,
    );
    return;
  }

  const res = await analyzeOne(root, runOpts);
  if (!res.picked) {
    console.log('docgen: nothing to do — all dirs are documented and fresh.');
    return;
  }
  if (res.skipped) {
    console.log(`docgen: SKIP ${res.picked} — ${res.message}`);
    return;
  }
  if (res.dryRun) {
    console.log(`docgen: would analyze ${res.picked} (${res.reason}, ${res.fileCount} files)`);
  } else {
    console.log(`docgen: wrote ${res.readmePath} (${res.fileCount} files, ${res.bytes} bytes)`);
  }
}

// Run main() when invoked as a script. Tests import this file and only
// use the exported helpers. We canonicalize both sides via realpathSync
// because macOS resolves `/tmp/...` (argv) → `/private/tmp/...` (import
// URL), and a literal === would mis-classify the script as imported.
function invokedAsScript() {
  if (!process.argv[1]) return false;
  try {
    const a = realpathSync(resolve(process.argv[1]));
    const b = realpathSync(fileURLToPath(import.meta.url));
    return a === b;
  } catch {
    return false;
  }
}
if (invokedAsScript()) {
  main().catch((err) => {
    console.error(err.message);
    process.exit(1);
  });
}
